namespace sv_1aa89c2caddb43dba6431df3b440e86b.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped service holding the currently selected warehouse.
/// Fires <see cref="OnChange"/> so every subscribed component re-renders
/// when the selection changes — even components that aren't in a
/// parent-child relationship.
/// Scoped lifetime = one instance per circuit = per-user isolation.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "wh-1", Name = "Warehouse A – East" },
        new() { Id = "wh-2", Name = "Warehouse B – West" },
        new() { Id = "wh-3", Name = "Warehouse C – Central" },
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_1aa89c2caddb43dba6431df3b440e86b.Services;

/// <summary>
/// Scoped service that tracks low-stock alert counts per warehouse.
/// Components subscribe to <see cref="OnAlertCountChanged"/> to be
/// notified when polling produces a new count — this is the cross-component
/// notification mechanism that keeps the sidebar badge and dashboard
/// in sync without any parent-child relationship.
/// </summary>
public class InventoryAlertService
{
    private static readonly Random s_random = new();

    public int CurrentAlertCount { get; private set; }

    public event Action? OnAlertCountChanged;

    /// <summary>
    /// Simulates a database query returning the number of items
    /// below minimum stock level for the given warehouse.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate latency + random result (0–15)
        var count = s_random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Fetches the latest count and notifies ALL subscribers.
    /// Called by the polling component; every other subscribed
    /// component (sidebar badge, etc.) updates automatically.
    /// </summary>
    public async Task RefreshAsync(string warehouseId)
    {
        CurrentAlertCount = await GetLowStockCountAsync(warehouseId);
        OnAlertCountChanged?.Invoke();
    }
}

