@* Interactive dropdown for warehouse selection.
   Rendered with @rendermode InteractiveServer in the static layout
   so it can handle change events. *@
@using sv_1aa89c2caddb43dba6431df3b440e86b.Services
@inject WarehouseState Warehouse
@implements IDisposable

<select class="form-select form-select-sm"
        value="@Warehouse.CurrentWarehouseId"
        @onchange="OnWarehouseChanged">
    @foreach (var wh in WarehouseState.AvailableWarehouses)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        // Subscribe so this component re-renders if another component
        // changes the warehouse (unlikely here, but keeps the pattern consistent).
        _handler = () => InvokeAsync(StateHasChanged);
        Warehouse.OnChange += _handler;
    }

    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
        {
            Warehouse.SetWarehouse(id);
        }
    }

    public void Dispose() => Warehouse.OnChange -= _handler;
}

@* Badge showing the current low-stock alert count.
   Subscribes to InventoryAlertService.OnAlertCountChanged so it updates
   whenever ANY component triggers a refresh — no parent-child wiring needed. *@
@using sv_1aa89c2caddb43dba6431df3b440e86b.Services
@inject InventoryAlertService Alerts
@implements IDisposable

@if (Alerts.CurrentAlertCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-1">@Alerts.CurrentAlertCount</span>
}
else
{
    <span class="badge bg-success rounded-pill ms-1">0</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        Alerts.OnAlertCountChanged += _handler;
    }

    public void Dispose() => Alerts.OnAlertCountChanged -= _handler;
}

@page "/dashboard"
@using sv_1aa89c2caddb43dba6431df3b440e86b.Services
@rendermode InteractiveServer
@inject WarehouseState Warehouse
@inject InventoryAlertService Alerts
@implements IDisposable

<PageTitle>Dashboard – @Warehouse.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">Current Warehouse</h5>
        <p class="card-text fs-4">@Warehouse.CurrentWarehouseName</p>
    </div>
</div>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">
            Low-Stock Alerts
            @if (Alerts.CurrentAlertCount > 0)
            {
                <span class="badge bg-danger ms-2">@Alerts.CurrentAlertCount items</span>
            }
            else
            {
                <span class="badge bg-success ms-2">All stocked</span>
            }
        </h5>
        <p class="text-muted mb-0">
            Polling every 10 seconds for warehouse <strong>@Warehouse.CurrentWarehouseId</strong>.
            Last checked: @_lastChecked?.ToString("T")
        </p>
    </div>
</div>

@code {
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private DateTime? _lastChecked;
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    protected override void OnInitialized()
    {
        // Re-render when warehouse changes (from the selector in the layout).
        _warehouseHandler = () => InvokeAsync(async () =>
        {
            // Warehouse changed — immediately refresh alerts for the new warehouse.
            await Alerts.RefreshAsync(Warehouse.CurrentWarehouseId);
            _lastChecked = DateTime.Now;
            StateHasChanged();
        });
        Warehouse.OnChange += _warehouseHandler;

        // Re-render when alert count changes (keeps this component in sync
        // even if another component triggered the refresh).
        _alertHandler = () => InvokeAsync(StateHasChanged);
        Alerts.OnAlertCountChanged += _alertHandler;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        // Initial fetch + start polling when the dashboard becomes visible.
        await Alerts.RefreshAsync(Warehouse.CurrentWarehouseId);
        _lastChecked = DateTime.Now;
        StateHasChanged();

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollAsync(_cts.Token);
    }

    private async Task PollAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await InvokeAsync(async () =>
                {
                    await Alerts.RefreshAsync(Warehouse.CurrentWarehouseId);
                    _lastChecked = DateTime.Now;
                    StateHasChanged();
                });
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose — polling stops when the user leaves the page.
        }
    }

    public void Dispose()
    {
        Warehouse.OnChange -= _warehouseHandler;
        Alerts.OnAlertCountChanged -= _alertHandler;
        _cts?.Cancel();
        _cts?.Dispose();
        _timer?.Dispose();
    }
}

